```javascript
function authenticateUser(username, password, callback) {
    db.findUser(username, function(err, user) {
        if (err) return callback(err);
        if (!user) return callback(new Error('User not found'));
        bcrypt.compare(password, user.hash, function(err, valid) {
            if (err) return callback(err);
            if (!valid) return callback(new Error('Invalid password'));
            jwt.sign({id: user.id}, SECRET, function(err, token) {
                if (err) return callback(err);
                audit.log('login', user.id, function(err) {
